member.summary:
Example usage:
using (var scanner = new FileScanner("path/to/file.bin"))
{
    var buffer = scanner.ReadBuffer(10, 16);
    var numberBytes = scanner.ReadNumber(100, 4);
    int number = BitConverter.ToInt32(numberBytes, 0);
}

Example usage:

var mem = new MemoryMeasurer();
mem.Measure("Start");

var timedFn = PerformanceUtils.MeasureTimeFn(() =>

{
    // Simulate work
    System.Threading.Thread.Sleep(300);
}, "Sleep300");

timedFn();

mem.Measure("After Sleep");

var timedCalc = PerformanceUtils.MeasureTimeFn(() =>
{
    return Enumerable.Range(0, 1000000).Sum(x => x);
}, "SumCalc");

var result = timedCalc();
Console.WriteLine($"Sum Result: {result}");

mem.Measure("After Calculation");

Example usage:

byte[] input = System.Text.Encoding.UTF8.GetBytes("abc");
byte[] digest = RIPEMD128.ComputeHash(input);
Console.WriteLine(BitConverter.ToString(digest).Replace("-", "").ToLower());
